// ── VEHICLE getter
function getVehicles() {
  try { const s=localStorage.getItem('ac_vehicles'); if(s) return JSON.parse(s); } catch(e){}
  return JSON.parse(JSON.stringify(AC_VEHICLES));
}

// ── WORKFLOW localStorage
function getWorkflow(stockNo) { return JSON.parse(localStorage.getItem('ac_wf_'+stockNo)||'{}'); }
function saveWorkflow(stockNo, data) { localStorage.setItem('ac_wf_'+stockNo, JSON.stringify(data)); }

// ── HANDOVERS
function saveHandover(stockNo, stageId, data) {
  const key='ac_ho_'+stockNo+'_'+stageId;
  localStorage.setItem(key, JSON.stringify({...data, ts:Date.now()}));
}
function getHandover(stockNo, stageId) {
  try { return JSON.parse(localStorage.getItem('ac_ho_'+stockNo+'_'+stageId)||'null'); } catch(e){ return null; }
}

// ── ASSIGN TASK
function assignTask(staffName, stockNo, stageId, stageName, note, vehicle) {
  const alerts = getAlerts();
  alerts.unshift({id:Date.now(),type:'handover',to:staffName,stockNo,stageId,stageName,note,
    vehicle:`${vehicle.registration} ${vehicle.make} ${vehicle.model}`,ts:Date.now(),read:false});
  localStorage.setItem('ac_alerts', JSON.stringify(alerts.slice(0,200)));
}

// ── ALERTS
function getAlerts() { return JSON.parse(localStorage.getItem('ac_alerts')||'[]'); }

// ── FORMAT GBP
function formatGBP(n) {
  if(!n && n!==0) return '—';
  return '£'+Number(n).toLocaleString('en-GB',{minimumFractionDigits:0,maximumFractionDigits:0});
}

// ── HOURS IN STAGE
function hoursInStage(stockNo, stageId) {
  const wf = getWorkflow(stockNo);
  const s = wf[stageId];
  if(!s||!s.startedAt) return 0;
  return Math.round((Date.now()-new Date(s.startedAt).getTime())/3600000);
}

